/**
 * @summary Get recent activity feed
 */
export const getGetRecentActivityUrl = (
  orgId: number,
  params?: GetRecentActivityParams,
) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/organizations/${orgId}/activity?${stringifiedParams}`
    : `/api/organizations/${orgId}/activity`;
};

export const getRecentActivity = async (
  orgId: number,
  params?: GetRecentActivityParams,
  options?: RequestInit,
): Promise<ActivityItem[]> => {
  return customFetch<ActivityItem[]>(getGetRecentActivityUrl(orgId, params), {
    ...options,
    method: "GET",
  });
};

